// canteenFeedTileLibrary — types + static seed for the Live Feed Tile
// library. The DB table `hammerex_feed_tile_library` is the runtime
// source of truth (managed via /admin/feed-tile-library); this file
// is the fallback seed when the DB is unreachable AND provides pure
// filter helpers used by client components.
//
// Every seed entry is Philip-approved per the image copyright rule
// (see feedback_image_copyright_risk_rules.md):
//   • AI-generated by Philip
//   • licensed stock
//   • trade-submitted with T&C warrant
//   • commissioned

export type FeedTileTextTone = "white" | "black" | "gray";

export type FeedTileLibraryImage = {
  /** Stable identifier — used as React key and analytics slug. */
  id: string;
  /** Canonical hosted URL (CDN or Supabase Storage). */
  url: string;
  /** Short human description shown as alt text + hover title. */
  alt: string;
  /** Recommended feed-text tone against this background. `white`
   *  (default) pairs with the standard dark scrim overlay; `black`
   *  is used for genuinely light images that would drown white
   *  text even with scrim (e.g. freshly-taped drywall). Render
   *  pipeline uses this to swap the scrim + text colour. */
  textTone?: FeedTileTextTone;
};

