/** Pure filter — return every library entry that lists this trade
 *  slug. Client callers pass the DB-loaded (or static-seed) list. */
export function filterByTrade(
  library: ReadonlyArray<FeedTileLibraryImage & { trade_slugs: string[] }>,
  tradeSlug: string | null | undefined
): FeedTileLibraryImage[] {
  if (!tradeSlug) return [];
  return library
    .filter((e) => e.trade_slugs.includes(tradeSlug))
    .map((e) => ({ id: e.id, url: e.url, alt: e.alt, textTone: e.textTone }));
}

/** Pure URL lookup — used by the canteen renderer to fetch the
 *  recommended textTone for a saved feed_tile_image_url. */
export function libraryEntryByUrl(
  library: ReadonlyArray<FeedTileLibraryImage & { trade_slugs: string[] }>,
  url: string | null | undefined
): FeedTileLibraryImage | null {
  if (!url) return null;
  return library.find((e) => e.url === url) ?? null;
}

// ── Back-compat exports ─────────────────────────────────────
// Existing call sites imported `libraryImagesForTrade` and the
// URL lookup with different signatures. Wrappers below preserve
// those signatures so unmigrated callers keep compiling; both
// wrappers use STATIC_FEED_TILE_LIBRARY (the seed) rather than DB.
// New code should call the pure functions above and pass a
// DB-loaded library array.

export function libraryImagesForTrade(tradeSlug: string | null | undefined): FeedTileLibraryImage[] {
  return filterByTrade(STATIC_FEED_TILE_LIBRARY, tradeSlug);
}

/** Single-arg URL lookup — back-compat shim for callers that don't
 *  yet receive the DB-loaded library as a prop. Uses the static seed.
 *  Prefer `libraryEntryByUrl(library, url)` (two-arg) in new code. */
export function libraryEntryByUrlStatic(url: string | null | undefined): FeedTileLibraryImage | null {
  return libraryEntryByUrl(STATIC_FEED_TILE_LIBRARY, url);
}
